// MapComponent.js
import React from "react";
import { MapContainer, TileLayer, Circle } from "react-leaflet";
import 'leaflet/dist/leaflet.css';

const MapComponent = ({ buses }) => {
  const center = [40.7128, -74.0060]; // NYC

  return (
    <MapContainer center={center} zoom={12} style={{ width: "100%", height: "100%" }}>
      <TileLayer
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" // Plain map
      />

      {buses && buses.map((bus, idx) => (
        <Circle
          key={`${bus.id}_${bus.timestamp || idx}`} // Unique key
          center={[bus.lat, bus.lon]}
          radius={50} // in meters
          color={
            bus.status === "ghost" ? "red" :
            bus.status === "anomaly" ? "orange" :
            "green"
          }
          fillOpacity={0.8}
        />
      ))}
    </MapContainer>
  );
};

export default MapComponent;
